import json
import pandas as pd
from io import StringIO

def validate_inputs(raw_leads, budget_threshold, source_criteria, timeout_duration=None):
    """验证输入数据格式与完整性"""
    validation_result = {
        "valid": True,
        "errors": [],
        "leads_count": 0,
        "budget_valid": False,
        "criteria_valid": False
    }

    try:
        # 解析原始线索数据
        if raw_leads.endswith('.csv'):
            df = pd.read_csv(StringIO(raw_leads))
        elif raw_leads.endswith('.json'):
            df = pd.read_json(StringIO(raw_leads))
        else:
            validation_result["errors"].append("不支持的文件格式")
            validation_result["valid"] = False
            return validation_result

        validation_result["leads_count"] = len(df)

        # 验证预算阈值
        try:
            budget = float(budget_threshold)
            if budget > 0:
                validation_result["budget_valid"] = True
            else:
                validation_result["errors"].append("预算阈值必须为正数")
        except ValueError:
            validation_result["errors"].append("预算阈值格式错误")

        # 验证来源分流标准
        if source_criteria and len(source_criteria.strip()) > 0:
            validation_result["criteria_valid"] = True
        else:
            validation_result["errors"].append("来源分流标准不能为空")

        # 验证超时时长（可选）
        if timeout_duration:
            try:
                hours = int(timeout_duration)
                if hours <= 0:
                    validation_result["errors"].append("超时时长必须为正整数")
            except ValueError:
                validation_result["errors"].append("超时时长格式错误")

        if validation_result["errors"]:
            validation_result["valid"] = False

    except Exception as e:
        validation_result["valid"] = False
        validation_result["errors"].append(f"数据解析失败: {str(e)}")

    return validation_result

import pandas as pd
import re
from io import StringIO

def clean_leads_data(raw_leads):
    """清洗原始线索数据"""
    try:
        if raw_leads.endswith('.csv'):
            df = pd.read_csv(StringIO(raw_leads))
        else:
            df = pd.read_json(StringIO(raw_leads))

        # 去重
        df = df.drop_duplicates(subset=['email', 'phone'], keep='first')

        # 标准化字段
        if 'email' in df.columns:
            df['email'] = df['email'].str.lower().str.strip()

        if 'phone' in df.columns:
            df['phone'] = df['phone'].astype(str).str.replace(r'[^0-9+]', '', regex=True)

        # 清理公司名称
        if 'company' in df.columns:
            df['company'] = df['company'].str.strip().str.title()

        # 处理缺失值
        required_fields = ['name', 'email', 'phone', 'source']
        for field in required_fields:
            if field in df.columns:
                df[field] = df[field].fillna('Unknown')

        # 添加处理时间戳
        df['processed_at'] = pd.Timestamp.now().isoformat()

        return {
            "success": True,
            "cleaned_data": df.to_dict('records'),
            "cleaned_count": len(df),
            "removed_duplicates": len(pd.read_csv(StringIO(raw_leads))) - len(df)
        }

    except Exception as e:
        return {
            "success": False,
            "error": str(e),
            "cleaned_data": [],
            "cleaned_count": 0
        }

