from datetime import datetime, timedelta
import json

def check_timeout(leads_data, timeout_hours):
    """检查线索跟进是否超时"""
    if not timeout_hours:
        return {"timeout_leads": [], "alerts": []}

    try:
        timeout_hours = int(timeout_hours)
        now = datetime.now()
        timeout_leads = []
        alerts = []

        for lead in leads_data:
            # 假设每个线索有last_contact_time字段
            if 'last_contact_time' in lead:
                last_contact = datetime.fromisoformat(lead['last_contact_time'].replace('Z', '+00:00'))
                time_diff = now - last_contact

                if time_diff.total_seconds() / 3600 > timeout_hours:
                    timeout_leads.append({
                        "id": lead.get('id'),
                        "name": lead.get('name'),
                        "timeout_hours": round(time_diff.total_seconds() / 3600, 1),
                        "last_contact": lead['last_contact_time']
                    })

                    alerts.append({
                        "level": "warning",
                        "message": f"线索 {lead.get('name')} 已超时 {round(time_diff.total_seconds() / 3600, 1)} 小时",
                        "timestamp": now.isoformat()
                    })

        return {
            "timeout_leads": timeout_leads,
            "alerts": alerts,
            "total_timeout": len(timeout_leads)
        }

    except Exception as e:
        return {
            "timeout_leads": [],
            "alerts": [{"level": "error", "message": f"超时检查失败: {str(e)}"}],
            "total_timeout": 0
        }

import json
from datetime import datetime

def format_final_report(llm_report, aggregate_data):
    """格式化最终输出报告"""
    try:
        report_data = json.loads(llm_report) if isinstance(llm_report, str) else llm_report

        final_report = {
            "final_status_report": {
                "generated_at": datetime.now().isoformat(),
                "total_leads_processed": aggregate_data.get('cleaned_stats', {}).get('cleaned_count', 0),
                "high_quality_leads": len([l for l in aggregate_data.get('scored_leads', []) if l.get('grade') == 'A']),
                "medium_quality_leads": len([l for l in aggregate_data.get('scored_leads', []) if l.get('grade') == 'B']),
                "low_quality_leads": len([l for l in aggregate_data.get('scored_leads', []) if l.get('grade') == 'C']),
                "team_distribution": {},
                "conversion_potential": report_data.get('conversion_potential', {})
            },
            "process_analytics": {
                "data_cleaning_efficiency": f"{aggregate_data.get('cleaned_stats', {}).get('cleaned_count', 0)}/{aggregate_data.get('cleaned_stats', {}).get('cleaned_count', 0) + aggregate_data.get('cleaned_stats', {}).get('removed_duplicates', 0)}",
                "scoring_distribution": report_data.get('scoring_distribution', {}),
                "team_assignment_summary": report_data.get('team_assignment_summary', {}),
                "flow_path_analysis": report_data.get('flow_path_analysis', {})
            },
            "alert_logs": {
                "timeout_alerts": aggregate_data.get('timeout_alerts', []),
                "process_errors": report_data.get('process_errors', []),
                "system_alerts": report_data.get('system_alerts', [])
            }
        }

        # 计算团队分布
        classified_leads = aggregate_data.get('classified_leads', [])
        team_counts = {}
        for lead in classified_leads:
            team = lead.get('team', 'Unknown')
            team_counts[team] = team_counts.get(team, 0) + 1

        final_report["final_status_report"]["team_distribution"] = team_counts

        return final_report

    except Exception as e:
        return {
            "final_status_report": {"error": f"报告生成失败: {str(e)}"},
            "process_analytics": {},
            "alert_logs": {"system_alerts": [{"level": "error", "message": f"格式化失败: {str(e)}"}]}
        }
